# Match a file path against a glob pattern supporting ** for directory traversal
glob_match() {
  local pattern="$1"
  local filepath="$2"

  # Build regex char-by-char to avoid bash parameter expansion pitfalls
  local regex=""
  local i=0
  local len=${#pattern}
  while [[ $i -lt $len ]]; do
    local c="${pattern:$i:1}"
    local next="${pattern:$((i+1)):1}"
    case "$c" in
      '*')
        if [[ "$next" == '*' ]]; then
          regex+=".*"
          i=$((i + 2))
          # Skip trailing / after **
          [[ "${pattern:$i:1}" == '/' ]] && i=$((i + 1))
          continue
        else
          regex+="[^/]*"
        fi
        ;;
      '?') regex+="[^/]" ;;
      '.') regex+="\\." ;;
      '+') regex+="\\+" ;;
      '(') regex+="\\(" ;;
      ')') regex+="\\)" ;;
      '[') regex+="\\[" ;;
      ']') regex+="\\]" ;;
      '{') regex+="\\{" ;;
      '}') regex+="\\}" ;;
      '^') regex+="\\^" ;;
      '$') regex+="\\$" ;;
      '|') regex+="\\|" ;;
      '\\') regex+="\\\\" ;;
      *) regex+="$c" ;;
    esac
    i=$((i + 1))
  done

  regex="^${regex}$"
  [[ "$filepath" =~ $regex ]]
}

